(function(w){"use strict";const ID="age";function compute(x){const birth=new Date(x.birth+"T00:00:00"),today=new Date(x.today+"T00:00:00");if(isNaN(birth)||isNaN(today)||birth>today)return{error:"생년월일과 기준일을 올바르게 입력해 주세요."};let age=today.getFullYear()-birth.getFullYear();const before=today.getMonth()<birth.getMonth()||(today.getMonth()===birth.getMonth()&&today.getDate()<birth.getDate());if(before)age--;return{age}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>생년월일</label><input type="date" class="hm-calc-input"></div><div class="hm-calc-field"><label>기준일</label><input type="date" class="hm-calc-input"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">만 나이 계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [birth,today]=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");today.value=api.localDateString();go.addEventListener("click",()=>{const r=compute({birth:birth.value,today:today.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("만 나이",`${r.age}세`));});}w.HM_CALC.register(ID,{compute,render});})(window);
